// ═══════════════════════════════════════════════════════════════════
// HOLLYWOOD SQUARES - Grid portrait collage (Animated)
// Synthograsizer Workflow Template
// ═══════════════════════════════════════════════════════════════════

const CW = 896;
const CH = 1152;

// Grid cell data — regenerated when cols/rows change
let cells = [];
let _prevCols = null;
let _prevRows = null;

// Seeded random for deterministic cell look
let _seed = 1;
function sRand() {
  _seed = (_seed * 16807 + 0) % 2147483647;
  return (_seed - 1) / 2147483646;
}
function sRandRange(a, b) { return a + sRand() * (b - a); }

function buildGrid(cols, rows) {
  cells = [];
  _seed = 42;
  let w = CW / cols;
  let h = CH / rows;
  for (let i = 0; i < cols; i++) {
    for (let j = 0; j < rows; j++) {
      cells.push({
        col: i, row: j,
        x: i * w, y: j * h, w: w, h: h,
        hue: sRandRange(0, 360),
        bgBright: sRandRange(60, 100),
        bgAlpha: sRandRange(15, 30),
        borderW: sRandRange(0, 6),
        skinBrightBase: sRandRange(10, 150),
        headSize: sRandRange(0.4, 0.66),
        bodySize: sRandRange(0.4, 0.5),
        headYDiv: sRandRange(1.35, 1.5),
        bodyYDiv: sRandRange(1.15, 1.35),
        strokeHue: sRandRange(0, 100),
        strokeSat: sRandRange(50, 256),
        strokeAlpha: sRandRange(0.45, 0.95),
        strokeW: sRandRange(0, 24),
        phase: sRandRange(0, 6.28),
        pulseSpeed: sRandRange(0.015, 0.04),
        bobAmt: sRandRange(2, 8),
        bobSpeed: sRandRange(0.02, 0.05)
      });
    }
  }
}

p.setup = function() {
  p.createCanvas(CW, CH);
  p.colorMode(p.HSB, 360, 255, 360, 100);
  buildGrid(3, 5);
};

p.draw = function() {
  let cols = parseInt(p.getSynthVar('cols')) || 3;
  let rows = parseInt(p.getSynthVar('rows')) || 5;
  let saturation = parseFloat(p.getSynthVar('saturation')) || 20;

  // Rebuild grid when structure changes
  if (cols !== _prevCols || rows !== _prevRows) {
    _prevCols = cols;
    _prevRows = rows;
    buildGrid(cols, rows);
  }

  let t = p.frameCount;

  p.background(0, 0, 350);

  for (let c of cells) {
    // Animated brightness pulse
    let pulse = Math.sin(t * c.pulseSpeed + c.phase) * 0.5 + 0.5;
    let bright = c.bgBright + pulse * 40;

    // Hue slowly drifts
    let hue = (c.hue + t * 0.15) % 360;

    // Cell background
    p.fill(hue, saturation * 2.5, bright + 200, c.bgAlpha + pulse * 8);
    p.stroke(0, 0, 30, 8);
    p.strokeWeight(c.borderW);
    p.rect(c.x, c.y, c.w, c.h);

    // Portrait position with bob
    let cx = c.x + c.w / 2;
    let headY = c.y + c.h / c.headYDiv;
    let bob = Math.sin(t * c.bobSpeed + c.phase) * c.bobAmt;
    let headR = Math.min(c.w, c.h) * c.headSize;

    // Glow behind the portrait head
    p.noStroke();
    let glowAlpha = 5 + pulse * 10;
    p.fill(hue, saturation * 3, bright + 100, glowAlpha);
    p.ellipse(cx, headY + bob, headR * 1.5, headR * 1.5);

    // Skin tone based on grid position
    let skinHue = (c.col + c.row) / (cols + rows) * 100;
    let skinSat = (c.col + c.row) / (cols + rows) * 160 + 10;
    let skinBright = c.skinBrightBase + pulse * 40 + 140;

    // Portrait head
    p.fill(skinHue, skinSat, skinBright);
    p.stroke(c.strokeHue, c.strokeSat, 256, c.strokeAlpha * (50 + pulse * 40));
    p.strokeWeight(c.strokeW * (0.6 + pulse * 0.4));
    p.ellipse(cx, headY + bob, headR);

    // Portrait body
    let bodyY = c.y + c.h / c.bodyYDiv;
    let bodyR = Math.min(c.w, c.h) * c.bodySize;
    p.noStroke();
    p.fill(skinHue, skinSat * 0.8, skinBright * 0.85);
    p.ellipse(cx, bodyY + bob * 0.5, bodyR);

    // Tiny eye dots with occasional blink
    let eyeY = headY + bob - headR * 0.05;
    let eyeSpread = headR * 0.14;
    let eyeSize = headR * 0.07;
    let blinkCycle = Math.sin(t * 0.025 + c.phase * 3);
    if (blinkCycle > -0.93) {
      p.fill(0, 0, 30);
      let eyeH = eyeSize * (0.8 + (blinkCycle + 1) * 0.2);
      p.ellipse(cx - eyeSpread, eyeY, eyeSize, eyeH);
      p.ellipse(cx + eyeSpread, eyeY, eyeSize, eyeH);
    }
  }
};
